 egin{tikzpicture}[scale=1, transform shape] 	ikzstyle{box} = [rectangle, rounded corners, minimum width=2cm, minimum height=0.8cm, draw, fill=gray!10, text centered, font= ] \useasboundingbox (-3.2, -2.8) rectangle (3.2, 2.8); 
ode[box] (quantum_queries_top) at (0, 2.2) {1.8cm{ Quantum Queries}}; 
ode[box] (classical_queries_right) at (2.2, 0) {1.8cm{ Classical Queries}}; 
ode[box] (quantum_samples_left) at (-2.2, 0) {1.8cm{ Quantum Function States}}; 
ode[box] (classical_samples_bottom) at (0, -2.2) {1.8cm{ Classical Samples}}; 
ode at (1.2, 1.2) [rotate=315] {1.0[1.0]{ $\geq$}}; 
ode at (1.2, -1.2) [rotate=45] {1.0[1.0]{ $\leq$}}; 
ode at (-1.2, -1.2) [rotate=-45] {1.0[1.0]{ $\geq$}}; 
ode at (-1.2, 1.2) [rotate=45] {1.0[1.0]{ $\leq$}}; 
ode at (0, 0) {	extcolor{burgundy}{1.0[1.5]{ $\lessgtr$}}}; \draw[-, burgundy, line width=1pt] (-0.15, -0.5) -- (0.15, 0.5); \end{tikzpicture} \caption{Property testing resource inequalities. The figure illustrates the connections between four different data access models in property testing, namely classical/quantum example/query access. Here, ``resource A $\geq$ resource B'' means that access to resource B can be simulated from access to resource A without any overhead. (For example, a single classical query can be used to simulate a single classical sample.) As a consequence of \Cref{inf-thm:separating-passive-quantum-from-query-classical-testing} and \cite{bernstein1997complexity, simon1997power, aaronson2015forrelation}, the only two among these access models that are not trivially comparable are in fact very incomparable. } \label{fig:different-access-models}

